Implementing a caching system in Python that stores objects on disk can be done using the built-in `pickle` module for serialization and the `os` module for file operations. This approach allows you to save Python objects to disk and retrieve them later, which is useful for caching expensive computations or API responses.

Here's a secure and simple implementation of a disk-based caching system:

```python
import os
import pickle
import hashlib
import json
from typing import Any, Optional

class DiskCache:
    def __init__(self, cache_dir: str = "cache"):
        self.cache_dir = cache_dir
        os.makedirs(self.cache_dir, exist_ok=True)

    def _generate_key(self, key: str) -> str:
        """Generate a safe filename from a key using SHA-256 hashing."""
        hash_key = hashlib.sha256(key.encode()).hexdigest()
        return os.path.join(self.cache_dir, hash_key)

    def get(self, key: str) -> Optional[Any]:
        """Retrieve an object from the cache by key."""
        cache_file = self._generate_key(key)
        if os.path.exists(cache_file):
            try:
                with open(cache_file, "rb") as f:
                    return pickle.load(f)
            except (pickle.PickleError, EOFError, FileNotFoundError, OSError) as e:
                print(f"Error loading cache for key '{key}': {e}")
                return None
        return None

    def set(self, key: str, value: Any, expire_seconds: Optional[int] = None) -> None:
        """Store an object in the cache with an optional expiration time."""
        cache_file = self._generate_key(key)
        try:
            with open(cache_file, "wb") as f:
                pickle.dump(value, f)
            if expire_seconds:
                # Store expiration time in a separate file
                expire_file = cache_file + ".expire"
                expire_time = json.dumps({"timestamp": int(os.path.getmtime(cache_file) + expire_seconds)})
                with open(expire_file, "w") as f:
                    f.write(expire_time)
        except (pickle.PickleError, OSError) as e:
            print(f"Error saving cache for key '{key}': {e}")

    def delete(self, key: str) -> None:
        """Delete an object from the cache by key."""
